import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';


import './AddPurchase.css';


const AddPurchase = ({ handleAdd, vendors }) => {

  const [newPurchase, setNewPurchase] = useState({
    id: '',
    location: '',
    materialid: '',
    quantity: '',
    
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAdd(newPurchase);
    resetForm();
  };

  const resetForm = () => {
    setNewPurchase({
        id: '',
        location: '',
        materialid: '',
        quantity: '',
    });
  };

  
  
  return (
    <div className="add-purchase-container">
      <h2 className="add-purchase-heading">Add Purchase</h2>
      <form className="add-purchase-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="id">Purchase ID:</label>
            <input
              type="text"
              id="id"
              name="id"
              value={newPurchase.id}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="name">Location:</label>
            <input
              type="text"
              id="location"
              name="location"
              value={newPurchase.location}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="materialid">Material ID:</label>
            <textarea
              id="materialid"
              name="materialid"
              value={newPurchase.materialid}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="quantity">Quantity:</label>
            <input
              type="text"
              id="quantity"
              name="quantity"
              value={newPurchase.quantity}
              onChange={handleInputChange}
              required
            />
          </div>
          
        
        </div>
        <button type="submit" className="add-purchase-btn">
          Add
        </button>
      </form>
    </div>
  );
};

export default AddPurchase;
